import os
import json
import sys

def translate_file(filepath, translations):
    """
    Translate a file with provided translation data.
    translations dict should have: title, description, content, seo_keywords
    """
    with open(filepath, 'r', encoding='utf-8') as f:
        data = json.load(f)

    data['title'] = translations['title']
    data['description'] = translations['description']
    data['content'] = translations['content']
    data['seo_keywords'] = translations['seo_keywords']

    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)

    print(f"✓ Translated: {os.path.basename(filepath)}")

